export type ParsedExecutePurchaseInstruction<
  TProgram extends string = typeof SOLANA_SPACE_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    buyer: TAccountMetas[0];
    /** Validated via has_one on listing. */
    seller: TAccountMetas[1];
    canvasState: TAccountMetas[2];
    /** The Metaplex Core asset being purchased */
    asset: TAccountMetas[3];
    /** The collection account */
    collection: TAccountMetas[4];
    listing: TAccountMetas[5];
    usdcMint: TAccountMetas[6];
    buyerUsdcAta: TAccountMetas[7];
    sellerUsdcAta: TAccountMetas[8];
    treasuryUsdcAta: TAccountMetas[9];
    tokenProgram: TAccountMetas[10];
    mplCoreProgram: TAccountMetas[11];
    systemProgram: TAccountMetas[12];
  };
  data: ExecutePurchaseInstructionData;
};

export function parseExecutePurchaseInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedExecutePurchaseInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 13) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 13,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      buyer: getNextAccount(),
      seller: getNextAccount(),
      canvasState: getNextAccount(),
      asset: getNextAccount(),
      collection: getNextAccount(),
      listing: getNextAccount(),
      usdcMint: getNextAccount(),
      buyerUsdcAta: getNextAccount(),
      sellerUsdcAta: getNextAccount(),
      treasuryUsdcAta: getNextAccount(),
      tokenProgram: getNextAccount(),
      mplCoreProgram: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getExecutePurchaseInstructionDataDecoder().decode(instruction.data),
  };
}
